### Object Utilities

Type-safe object manipulation with deep path access.

```typescript
import {
  getProperty,
  setProperty,
  objectKeys,
  objectEntries,
  objectValues,
  keyBy,
  isObject,
  assertObject,
  requireAll,
  deepFreeze,
} from '@belt/tools';

// Deep property access (type-safe)
const street = getProperty(user, 'address.street');
const city = getProperty(user, 'address.city', true); // Allow falsy values

// Set nested properties
setProperty(train, 'metadata.lastInspection', new Date());

// Object manipulation
const keys = objectKeys(train); // Type-safe keys
const entries = objectEntries(train); // Typed entries
const values = objectValues(train); // Typed values

// Array to object by key
const trainsById = keyBy(trains, 'id');
// Or with function
const trainsByName = keyBy(trains, (t) => t.name);

// Type guards
if (isObject(value)) {
  // value is UnknownRecord
}

// Assert object with no falsy values
const validated = requireAll({
  id: train.id,
  name: train.name,
  mileage: train.mileage,
});

// Deep freeze (immutability)
const frozen = deepFreeze(config);
```

**Path Examples:**
```typescript
type User = {
  id: string;
  profile: {
    address: {
      street: string;
      city: string;
    };
  };
};

// All paths are type-checked
getProperty(user, 'id');                    // ✓ string
getProperty(user, 'profile.address.city');  // ✓ string
getProperty(user, 'profile.invalid');       // ✗ Type error
```

