### Type Utilities

Advanced TypeScript type helpers.

```typescript
import type {
  Paths,          // All dot-notation paths of object
  PathType,       // Type at specific path
  Compute,        // Flatten intersection types
  Writable,       // Remove readonly modifiers
  Falsy,          // Union of falsy values
  InferType,      // Infer type from schema
  UnknownRecord,  // { [key: string]: unknown }
  AnyRecord,      // { [key: string]: any }
  MaybePromise,   // T | Promise<T>
  MaybeArray,     // T | T[]
  PromiseValue,   // Extract Promise<T> → T
  Simplify,       // Flatten complex types
  Merge,          // Deep merge two types
  PartialFields,  // Make specific fields optional
  NullableToPartial, // Convert nullable to optional
  UnionToIntersection, // Union → Intersection
  CastUnknown,    // Cast if unknown
  SerializableOnly, // Only serializable fields
} from '@belt/tools';

// Example: Paths
type User = {
  id: string;
  profile: {
    address: {
      street: string;
    };
  };
};

type UserPaths = Paths<User>;
// 'id' | 'profile' | 'profile.address' | 'profile.address.street'

type StreetType = PathType<User, 'profile.address.street'>;
// string

// Example: Compute (flatten intersections)
type A = { a: number };
type B = { b: string };
type Flat = Compute<A & B>; // { a: number; b: string }

// Example: Writable
type ReadOnly = { readonly id: string; readonly name: string };
type Mutable = Writable<ReadOnly>; // { id: string; name: string }

// Example: PartialFields
type Train = { id: string; name: string; metadata: object };
type Optional = PartialFields<Train, ['metadata']>;
// { id: string; name: string; metadata?: object }
```

**Type Guards:**
```typescript
import { isFalsy } from '@belt/tools';
import type { Falsy } from '@belt/tools';

// All falsy values
const falsyValues: Falsy = false | '' | null | undefined | 0 | 0n | NaN;

if (isFalsy(value)) {
  // value is one of the falsy values
}
```

