### Other Utilities

```typescript
import { delay, maskData, getTypeOf, createProxy } from '@belt/tools';

// Async delay
await delay(500); // Wait 500ms
await delay();    // Default 500ms

// Mask sensitive data for logging
const masked = maskData({
  password: 'secret123',
  email: 'user@example.com',
  nested: { token: 'abc123' },
});
// { password: 'String', email: 'String', nested: { token: 'String' } }

// Get type name
getTypeOf(null);           // 'Null'
getTypeOf(undefined);      // 'Undefined'
getTypeOf(new Date());     // 'Date'
getTypeOf({});             // 'Object'
getTypeOf([]);             // 'Array'
getTypeOf(NaN);            // 'NaN'

// Lazy initialization
const lazyConfig = createProxy(() => loadConfig());
// Config is only loaded on first access
```
